external_knowledge:
- Participants with consent_status = 1 have given consent; 
- Location refers to the city where the participant is located; 
- Average alcohol consumption > 5 drinks per day is considered high; 
- Baseline survey type is the first survey taken by the participant.

sql:
SELECT participant_id
FROM participants
ORDER BY participant_id;

SELECT issue_description
FROM data_quality
WHERE resolution = 'unresolved';

external_knowledge:
; Participants who have given their consent are those who have agreed to participate in the study or survey; 
; Completed a follow-up survey refers to participants who have finished answering or responding to the follow-up survey; 
; Unresolved issues pertain to missing data that has not been resolved or completed by the participant.
